import sys
from typing import List

class Solution:
    def arrayRankTransform(self, arr: List[int]) -> List[int]:
        if not arr:
            return []

        sorted_arr = sorted((x, i) for i, x in enumerate(arr))
        rank = {}
        curr_rank = 1
        for i, (val, _) in enumerate(sorted_arr):
            if i > 0 and sorted_arr[i-1][0] != val:
                curr_rank = i + 1
            rank[val] = curr_rank

        return [rank[x] for x in arr]

