#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> arrayRankTransform(vector<int>& arr) {
        if (arr.empty()) {
            return {};
        }

        vector<pair<int, int>> sorted_arr;
        for (int i = 0; i < arr.size(); i++) {
            sorted_arr.emplace_back(arr[i], i);
        }
        sort(sorted_arr.begin(), sorted_arr.end());

        unordered_map<int, int> rank;
        int curr_rank = 1;
        for (int i = 0; i < sorted_arr.size(); i++) {
            if (i > 0 && sorted_arr[i-1].first != sorted_arr[i].first) {
                curr_rank = i + 1;
            }
            rank[sorted_arr[i].first] = curr_rank;
        }

        vector<int> result(arr.size());
        for (int i = 0; i < arr.size(); i++) {
            result[i] = rank[arr[i]];
        }
        return result;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    Solution sol;
    vector<int> ans = sol.arrayRankTransform(arr);
    cout << ans.size() << "\n";
    for (int i = 0; i < ans.size(); i++) {
        cout << ans[i] << (i == ans.size() - 1 ? "" : " ");
    }
    cout << "\n";
    return 0;
}
